package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetSkipHeaderRecord_defaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    public void testGetSkipHeaderRecord_withSkipHeaderRecordTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(true);
        assertTrue(format.getSkipHeaderRecord());
    }

    @Test
    public void testGetSkipHeaderRecord_withSkipHeaderRecordFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withSkipHeaderRecord(false);
        assertFalse(format.getSkipHeaderRecord());
    }

    @Test
    public void testGetSkipHeaderRecord_chainedWithOtherSettings() {
        CSVFormat format = CSVFormat.DEFAULT
                .withSkipHeaderRecord(true)
                .withDelimiter(';')
                .withIgnoreEmptyLines(true);
        assertTrue(format.getSkipHeaderRecord());
    }
}
